sp_widget.client_script:
api.controller=function() {
  /* widget controller */
  var c = this;
};

sp_widget.css:
.dashboard{

    padding:60px;
    background:linear-gradient(135deg,#f5f7fa,#eef3f8);
    min-height:100vh;

}

.dashboard h1{

    text-align:center;
    color:#0F4C81;
    font-size:46px;
    margin-bottom:15px;
    font-weight:700;

}

.dashboard p{

    text-align:center;
    color:#666;
    font-size:18px;
    max-width:850px;
    margin:0 auto 55px auto;
    line-height:1.8;

}

.dashboard-grid{

    display:flex;
    justify-content:center;
    gap:30px;
    flex-wrap:wrap;
    margin-bottom:70px;

}

.dash-card{

    width:260px;
    background:#ffffff;
    border-radius:16px;
    padding:35px;
    text-align:center;
    box-shadow:0 10px 25px rgba(15,76,129,.12);
    transition:all .35s ease;
    border-top:6px solid #0F4C81;
    position:relative;
    overflow:hidden;

}

.dash-card::before{

    content:"";
    position:absolute;
    top:0;
    left:-100%;
    width:100%;
    height:100%;
    background:linear-gradient(90deg,
    transparent,
    rgba(255,255,255,.45),
    transparent);

    transition:.7s;

}

.dash-card:hover::before{

    left:100%;

}

.dash-card:hover{

    transform:translateY(-10px) scale(1.03);
    box-shadow:0 18px 35px rgba(15,76,129,.18);

}

.dash-card h2{

    color:#666;
    font-size:20px;
    margin-bottom:18px;

}

.dash-card h3{

    color:#0F4C81;
    font-size:48px;
    margin:0;
    font-weight:bold;

}

.analytics-section{

    background:#ffffff;
    border-radius:18px;
    padding:55px;
    text-align:center;
    box-shadow:0 12px 28px rgba(15,76,129,.12);
    transition:.35s;
    border-top:6px solid #D4A017;

}

.analytics-section:hover{

    transform:translateY(-8px);

}

.analytics-section h2{

    color:#0F4C81;
    font-size:34px;
    margin-bottom:18px;

}

.analytics-section p{

    color:#666;
    font-size:18px;
    max-width:800px;
    margin:0 auto 35px auto;
    line-height:1.8;

}

.analytics-btn{

    background:linear-gradient(135deg,#0F4C81,#1E6BB8);
    color:white;
    border:none;
    border-radius:10px;
    padding:18px 42px;
    font-size:18px;
    font-weight:bold;
    cursor:pointer;
    transition:.35s;
    box-shadow:0 8px 18px rgba(15,76,129,.25);

}

.analytics-btn:hover{

    transform:translateY(-4px);
    box-shadow:0 14px 28px rgba(15,76,129,.35);
    background:linear-gradient(135deg,#0B3A62,#0F4C81);

}

@media(max-width:768px){

    .dashboard{

        padding:30px 20px;

    }

    .dashboard h1{

        font-size:34px;

    }

    .dashboard-grid{

        flex-direction:column;
        align-items:center;

    }

    .dash-card{

        width:100%;
        max-width:340px;

    }

    .analytics-section{

        padding:35px 20px;

    }

    .analytics-section h2{

        font-size:28px;

    }

    .analytics-btn{

        width:100%;

    }

}

sp_widget.script:
(function() {

    data.total = 0;
    data.approved = 0;
    data.completed = 0;

    var gr = new GlideRecord('x_1958816_enterp_0_network_request');
    gr.query();

    while (gr.next()) {

        data.total++;

        var state = gr.getDisplayValue('state');

        if (state == "Approved")
            data.approved++;

        if (state == "Completed")
            data.completed++;

    }

})();
